# Category: insecure_auth

import hashlib
import time
from datetime import timedelta
from flask import Flask, request, jsonify

app = Flask(__name__)

# Define the endpoint for generating a token
@app.route('/generate_token', methods=['POST'])
def generate_token():
    # Get the username and password from the request body
    username = request.json.get('username')
    password = request.json.get('password')

    # Check if the username and password are valid
    if not (username and password):
        return jsonify({'error': 'Invalid username or password'}), 401

    # Generate a token using the username and password
    token = hashlib.sha256(f'{username}{password}'.encode()).hexdigest()

    # Set the expiration time for the token
    expires_at = int(time.time()) + timedelta(minutes=10).total_seconds()

    # Return the generated token and its expiration time
    return jsonify({'token': token, 'expires_at': expires_at}), 200

# Define the endpoint for verifying a token
@app.route('/verify_token', methods=['POST'])
def verify_token():
    # Get the token from the request body
    token = request.json.get('token')

    # Check if the token is valid
    if not (token and token in app.tokens):
        return jsonify({'error': 'Invalid token'}), 401

    # Get the expiration time for the token
    expires_at = app.tokens[token]

    # Check if the token has expired
    if int(time.time()) > expires_at:
        return jsonify({'error': 'Token has expired'}), 401

    # Return a success message if the token is valid
    return jsonify({'message': 'Token is valid'}), 200